import React, { useState, useEffect } from 'react';

function Header() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeLink, setActiveLink] = useState('home');
  const [cartCount, setCartCount] = useState(0);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { id: 'home', label: 'Home', icon: '🏠' },
    { id: 'shop', label: 'Shop', icon: '🛍️' },
    { id: 'about', label: 'About', icon: '💐' },
    { id: 'contact', label: 'Contact', icon: '💌' },
  ];

  return (
    <>
      {/* Top Announcement Bar */}
      <div className="announcement-bar">
        <div className="announcement-content">
          <span className="announcement-text">
            🌸 Free delivery on orders over $50! Use code: BLOOM50
          </span>
          <span className="announcement-text">
            🌿 Fresh flowers delivered daily
          </span>
          <span className="announcement-text">
            💝 Same-day delivery available
          </span>
        </div>
      </div>

      {/* Main Header */}
      <header className={`header ${isScrolled ? 'header-scrolled' : ''}`}>
        <div className="header-content">
          {/* Logo Section */}
          <div className="logo-section">
            <div className="logo-icon-wrapper">
              <span className="logo-icon">🌼</span>
              <span className="logo-sparkle">✨</span>
            </div>
            <div className="logo-text">
              <h1 className="logo-title">Bloom Haven</h1>
              <p className="logo-subtitle">Fresh Flowers & Bouquets</p>
            </div>
          </div>

          {/* Desktop Navigation */}
          <nav className="nav-desktop">
            {navLinks.map((link) => (
              <a
                key={link.id}
                href={`#${link.id}`}
                className={`nav-link ${activeLink === link.id ? 'active' : ''}`}
                onClick={(e) => {
                  e.preventDefault();
                  setActiveLink(link.id);
                }}
              >
                <span className="nav-icon">{link.icon}</span>
                {link.label}
                {activeLink === link.id && <span className="nav-indicator"></span>}
              </a>
            ))}
          </nav>

          {/* Action Buttons */}
          <div className="header-actions">
            {/* Search Quick Toggle */}
            <button className="action-btn search-btn" aria-label="Search">
              <svg className="action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </button>

            {/* Wishlist */}
            <button 
              className="action-btn wishlist-btn" 
              aria-label="Wishlist"
              onClick={() => setIsWishlistOpen(!isWishlistOpen)}
            >
              <svg className="action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
              </svg>
              <span className="badge">3</span>
            </button>

            {/* Cart */}
            <button className="action-btn cart-btn" aria-label="Cart">
              <svg className="action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 100 4 2 2 0 000-4z" />
              </svg>
              <span className="badge">{cartCount}</span>
            </button>

            {/* User Profile */}
            <button className="action-btn user-btn" aria-label="User profile">
              <div className="user-avatar">
                <svg className="action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                </svg>
              </div>
            </button>

            {/* Mobile Menu Toggle */}
            <button 
              className="action-btn mobile-menu-btn"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-label="Toggle menu"
            >
              <svg className="action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor">
                {isMobileMenuOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>

        {/* Mobile Navigation */}
        <div className={`mobile-nav ${isMobileMenuOpen ? 'open' : ''}`}>
          <div className="mobile-nav-content">
            {navLinks.map((link) => (
              <a
                key={link.id}
                href={`#${link.id}`}
                className={`mobile-nav-link ${activeLink === link.id ? 'active' : ''}`}
                onClick={(e) => {
                  e.preventDefault();
                  setActiveLink(link.id);
                  setIsMobileMenuOpen(false);
                }}
              >
                <span className="mobile-nav-icon">{link.icon}</span>
                {link.label}
              </a>
            ))}
            <div className="mobile-nav-divider"></div>
            <div className="mobile-nav-actions">
              <a href="#wishlist" className="mobile-nav-link">
                <span className="mobile-nav-icon">💝</span>
                Wishlist (3)
              </a>
              <a href="#account" className="mobile-nav-link">
                <span className="mobile-nav-icon">👤</span>
                My Account
              </a>
              <a href="#orders" className="mobile-nav-link">
                <span className="mobile-nav-icon">📦</span>
                Orders
              </a>
            </div>
          </div>
        </div>
      </header>
    </>
  );
}

export default React.memo(Header);
